// Reúne todos los datos necesarios para el AI Agent en un objeto limpio
const normalData = $('📋 Normalizar datos').item.json;
const contactData = items[0].json;

// Parsear historial de conversación (guardado como JSON string en respond.io)
let history = [];
try {
  history = JSON.parse(contactData.conversation_history || '[]');
  if (!Array.isArray(history)) history = [];
} catch(e) {
  history = [];
}

// Añadir el mensaje actual del lead al historial
history.push({
  role: 'user',
  content: normalData.message_text,
  timestamp: new Date().toISOString()
});

// Mantener solo los últimos 10 mensajes para no saturar el contexto del AI
if (history.length > 10) {
  history = history.slice(-10);
}

// Determinar entry_type basado en qué rama del Switch tomó
// Si el contacto ya tenía entry_type guardado, usarlo. Si no, inferir del switch.
let entry_type = contactData.entry_type || '';
if (!entry_type || entry_type === '') {
  const msgLower = normalData.message_text.toLowerCase();
  if (msgLower.includes('quiero')) entry_type = '1';
  else if (/precio|curso|comprar|cómo funciona|que incluye|cuánto|cuanto|info|información|programa/.test(msgLower)) entry_type = '4';
  else entry_type = '3'; // catch-all por defecto
}

return [{
  json: {
    // Identificadores
    contact_id: normalData.contact_id,
    contact_name: normalData.contact_name,
    conversation_id: normalData.conversation_id,
    // Estado del lead
    lifecycle_stage: contactData.lifecycle_stage,
    lead_temperature: contactData.lead_temperature,
    main_problem: contactData.main_problem || '',
    entry_type: entry_type,
    // Contexto conversacional
    conversation_history: history,
    conversation_history_str: JSON.stringify(history),
    conversation_summary: contactData.conversation_summary || '',
    // Mensaje actual
    message_text: normalData.message_text
  }
}];

