// Parsea el JSON devuelto por el AI y prepara el objeto final
const aiRaw = items[0].json.choices[0].message.content;
const contextData = $('🧠 Construir contexto IA').item.json;

let aiResponse;
try {
  aiResponse = JSON.parse(aiRaw);
} catch(e) {
  // Fallback si el parsing falla (muy raro con response_format json_object)
  console.log('ERROR parsing AI response:', e.message, 'Raw:', aiRaw);
  aiResponse = {
    messages: [aiRaw.substring(0, 500)], // Trunca por si acaso
    send_video: false,
    send_audio: false,
    send_calendly: false,
    new_stage: contextData.lifecycle_stage,
    new_temperature: contextData.lead_temperature,
    detected_problem: contextData.main_problem,
    conversation_summary: contextData.conversation_summary
  };
}

// Actualizar historial con los mensajes del bot para persistir en respond.io
let history = contextData.conversation_history || [];
const botMessages = aiResponse.messages || [];
botMessages.forEach(msg => {
  if (msg && msg.trim()) {
    history.push({
      role: 'assistant',
      content: msg,
      timestamp: new Date().toISOString()
    });
  }
});
// Mantener últimos 10 mensajes
if (history.length > 10) history = history.slice(-10);

// Si se envía vídeo, forzar stage a video_enviado independientemente de lo que diga el AI
let finalStage = aiResponse.new_stage || contextData.lifecycle_stage;
if (aiResponse.send_video) finalStage = 'video_enviado';
if (aiResponse.send_audio) finalStage = 'cualificado';
if (aiResponse.send_calendly && !aiResponse.send_audio) finalStage = 'llamada_agendada';

return [{
  json: {
    // Identificadores (propagados del contexto)
    contact_id: contextData.contact_id,
    contact_name: contextData.contact_name,
    conversation_id: contextData.conversation_id,
    entry_type: contextData.entry_type,
    // Acciones del AI
    messages: aiResponse.messages || [],
    send_video: aiResponse.send_video || false,
    send_audio: aiResponse.send_audio || false,
    send_calendly: aiResponse.send_calendly || false,
    // Nuevo estado a guardar en respond.io
    new_stage: finalStage,
    new_temperature: aiResponse.new_temperature || contextData.lead_temperature,
    detected_problem: aiResponse.detected_problem || contextData.main_problem || '',
    conversation_summary: aiResponse.conversation_summary || contextData.conversation_summary || '',
    // Historial actualizado para persistir
    updated_history: JSON.stringify(history)
  }
}];

// Envía cada mensaje del array con delay entre ellos para simular escritura natural
const data = items[0].json;
const messages = data.messages || [];
const contactId = data.contact_id;
const channelId = process.env.RESPOND_IO_CHANNEL_ID;
const apiKey = process.env.RESPOND_IO_API_KEY;

if (!contactId) {
  console.log('ERROR: No contact_id disponible');
  return [{ json: { ...data, message_results: [], error: 'No contact_id' } }];
}

const results = [];

for (let i = 0; i < messages.length; i++) {
  const msg = messages[i];
  if (!msg || msg.trim() === '') continue;

  // Delay entre mensajes para simular escritura natural (1.5 segundos por mensaje)
  if (i > 0) {
    await new Promise(r => setTimeout(r, 1500));
  }

  try {
    const response = await $helpers.httpRequest({
      method: 'POST',
      url: `https://api.respond.io/v2/contact/${contactId}/message`,
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        channelId: channelId,
        message: {
          type: 'text',
          text: msg
        }
      })
    });
    results.push({ success: true, message: msg, index: i });
  } catch(e) {
    results.push({ success: false, message: msg, index: i, error: e.message });
    console.log(`ERROR enviando mensaje ${i}:`, e.message);
  }
}

return [{ json: { ...data, message_results: results } }];
